#!/usr/bin/env node
import fs from 'node:fs'
import path from 'node:path'
import { spawnSync } from 'node:child_process'
import { fileURLToPath } from 'node:url'
import {
  extractReqIdFromHookInput,
  resolveWorkDir,
  resolveWorkDirByReqId,
} from './phase2-hook-utils.mjs'

const SCRIPT_NAME = 'phase0-pre-init-workdir'
const SCRIPT_DIR = path.dirname(fileURLToPath(import.meta.url))
const PROJECT_DIR = path.resolve(SCRIPT_DIR, '..', '..')
const LOG_DIR = path.join(PROJECT_DIR, 'logs')
const HOOK_LOG_FILE = path.join(LOG_DIR, 'phase0-hook.log')
const CREATE_DIR_SCRIPT = path.join(
  PROJECT_DIR,
  '.specify',
  'scripts',
  'bash',
  'common_bash',
  'create_req_structure.sh',
)

function ensureLogDir() {
  fs.mkdirSync(LOG_DIR, { recursive: true })
}

function writeLog(msg) {
  ensureLogDir()
  const line = `[${new Date().toISOString()}] [${SCRIPT_NAME}] ${msg}\n`
  fs.appendFileSync(HOOK_LOG_FILE, line, 'utf8')
  console.error(`[${SCRIPT_NAME}] ${msg}`)
}

function ok() {
  process.stdout.write(JSON.stringify({ continue: true }))
}

function fail(reason, label = '阻断初始化 Skill') {
  const msg = String(reason || '未知错误')
  const prefix = typeof label === 'string' && label.trim() ? label.trim() : '阻断初始化 Skill'
  writeLog(`${prefix}：${msg}`)
  process.stdout.write(JSON.stringify({ continue: false, stopReason: msg }))
  process.exit(2)
}

async function readStdin() {
  const chunks = []
  for await (const c of process.stdin) chunks.push(c)
  return Buffer.concat(chunks).toString('utf8')
}

function isInitSkill(input) {
  if (input?.hook_event_name !== 'PreToolUse') return false
  if (input?.tool_name !== 'Skill') return false
  const skill = typeof input?.tool_input?.skill === 'string'
    ? input.tool_input.skill.trim()
    : ''
  return skill === '初始化'
}

function isSkillPreHook(input) {
  return input?.hook_event_name === 'PreToolUse' && input?.tool_name === 'Skill'
}

function getSkillName(input) {
  return typeof input?.tool_input?.skill === 'string' ? input.tool_input.skill.trim() : ''
}

function safeReadJson(filePath) {
  try {
    if (!fs.existsSync(filePath)) return null
    return JSON.parse(fs.readFileSync(filePath, 'utf8'))
  } catch {
    return null
  }
}

async function resolveWorkDirForSkill(input, projectDir) {
  let workDir = resolveWorkDir(
    input?.tool_input?.args,
    process.env.REQUIREMENT_WORK_DIR,
    input?.cwd,
    typeof input?.tool_input === 'object' && input.tool_input != null
      ? JSON.stringify(input.tool_input)
      : '',
  )
  if (workDir) return workDir

  const reqId = await extractReqIdFromHookInput(input)
  if (!reqId) return ''
  return resolveWorkDirByReqId(projectDir, reqId)
}

function hasInitEvidence(workDir) {
  if (!workDir) return false
  const phaseStatusPath = path.join(workDir, 'phase_status.json')
  const j = safeReadJson(phaseStatusPath)
  if (!j || typeof j !== 'object') return false
  const p1 = j.phase1
  if (!p1 || typeof p1 !== 'object') return false
  // 只要 phase1 结构存在即视为已执行过初始化入口
  return typeof p1.status === 'string' && p1.status.trim().length > 0
}

function resolveInitializedWorkDirFallback(input, projectDir, preferredWorkDir) {
  if (hasInitEvidence(preferredWorkDir)) {
    return { workDir: preferredWorkDir, source: 'resolved' }
  }
  // 关键约束：如果已解析出当前请求的工作目录，则初始化证据必须来自该目录；
  // 严禁跨 req 使用其它目录的初始化证据放行。
  if (preferredWorkDir) {
    return { workDir: preferredWorkDir, source: 'resolved:no_init' }
  }
  // 未定位到当前请求所属工作目录时，直接判定无证据；
  // 禁止通过任意目录锁进行跨需求兜底放行。
  return { workDir: '', source: 'unresolved' }
}

function buildGateBlockReason(skillName, evidenceSource) {
  // 失败原因拆分：避免把“目录未定位”误报为“未初始化”。
  if (evidenceSource === 'unresolved') {
    return [
      `当前禁止调用“${skillName}”：未能定位本次调用对应的需求工作目录。`,
      '请在调用参数中显式传入 req_id（例如：req_id=RAN-6166005）后重试。',
      '若你已执行过“初始化”，请确认本次调用与初始化使用的是同一个 req_id。',
    ].join(' ')
  }
  return [
    `阶段1第一步必须先调用“初始化”Skill。当前禁止直接调用“${skillName}”。`,
    '请先执行“初始化”，再继续查询类技能。',
  ].join(' ')
}

function ensureExistingWorkDirIsDirectory(workDir) {
  if (!fs.existsSync(workDir)) return false
  const stat = fs.statSync(workDir)
  if (!stat.isDirectory()) {
    fail(`需求工作目录不是目录：${workDir}`)
  }
  return true
}

function runCreateScript(reqId) {
  if (!fs.existsSync(CREATE_DIR_SCRIPT)) {
    fail(`目录初始化脚本不存在：${CREATE_DIR_SCRIPT}`)
  }
  const result = spawnSync('bash', [CREATE_DIR_SCRIPT, reqId], {
    cwd: PROJECT_DIR,
    encoding: 'utf8',
  })
  if (result.error) {
    fail(`执行目录初始化脚本异常：${result.error.message}`)
  }
  if (result.status !== 0) {
    const stdout = (result.stdout || '').trim()
    const stderr = (result.stderr || '').trim()
    fail(
      `目录初始化脚本执行失败（exit=${result.status}）\nstdout:\n${stdout || '<empty>'}\nstderr:\n${stderr || '<empty>'}`,
    )
  }
}

async function main() {
  let input = {}
  try {
    input = JSON.parse((await readStdin()) || '{}')
  } catch {
    ok()
    return
  }

  if (!isSkillPreHook(input)) {
    ok()
    return
  }

  const skillName = getSkillName(input)
  const gatedSkills = new Set(['查询需求信息', '查询iCenter页面内容', '查询icenter页面内容'])
  if (skillName !== '初始化' && gatedSkills.has(skillName)) {
    const inferredWorkDir = await resolveWorkDirForSkill(input, PROJECT_DIR)
    const evidence = resolveInitializedWorkDirFallback(input, PROJECT_DIR, inferredWorkDir)
    if (evidence.source === 'unresolved') {
      writeLog(
        `查询类技能门禁拦截(目录未定位) skill=${skillName} inferred_work_dir=${inferredWorkDir || '<empty>'} evidence_work_dir=${evidence.workDir || '<empty>'} source=${evidence.source}`,
      )
      fail(buildGateBlockReason(skillName, evidence.source), '阻断查询类 Skill')
    }
    const initialized = hasInitEvidence(evidence.workDir)
    writeLog(
      `查询类技能门禁检查 skill=${skillName} inferred_work_dir=${inferredWorkDir || '<empty>'} evidence_work_dir=${evidence.workDir || '<empty>'} source=${evidence.source} initialized=${initialized}`,
    )
    if (!initialized) {
      fail(buildGateBlockReason(skillName, evidence.source), '阻断查询类 Skill')
    }
    ok()
    return
  }

  if (!isInitSkill(input)) {
    ok()
    return
  }

  const reqId = await extractReqIdFromHookInput(input)
  if (!reqId) {
    fail('无法从初始化 Skill 输入中提取需求ID，已停止执行。')
  }

  const workDir = resolveWorkDirByReqId(PROJECT_DIR, reqId)
  if (!workDir) {
    fail(`根据需求ID计算工作目录失败：req_id=${reqId}`)
  }

  writeLog(`开始校验需求工作目录 req_id=${reqId} work_dir=${workDir}`)
  const exists = ensureExistingWorkDirIsDirectory(workDir)
  if (exists) {
    writeLog('需求工作目录已存在，跳过创建脚本执行')
    ok()
    return
  }

  writeLog(`需求工作目录不存在，开始执行脚本：bash ${CREATE_DIR_SCRIPT} ${reqId}`)
  runCreateScript(reqId)

  if (!ensureExistingWorkDirIsDirectory(workDir)) {
    fail(`脚本执行完成后未找到需求工作目录：${workDir}`)
  }

  writeLog('需求工作目录创建完成')
  ok()
}

main().catch(error => {
  fail(String(error?.message || error))
})

